import{_ as l,o as i,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const b=JSON.parse('{"title":"分片副本与高可用","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/11-ElasticSearch学习/05-分片副本与高可用.md","filePath":"语言/java/11-ElasticSearch学习/05-分片副本与高可用.md","lastUpdated":1776149370000}'),t={name:"语言/java/11-ElasticSearch学习/05-分片副本与高可用.md"};function h(_,a,n,s,d,c){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="分片副本与高可用" tabindex="-1">分片副本与高可用 <a class="header-anchor" href="#分片副本与高可用" aria-label="Permalink to “分片副本与高可用”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>分片用于横向拆分数据，副本用于提升容错与读能力。<br> 它们共同支撑 ES 的扩展性和高可用能力。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>分片和副本是 ElasticSearch 集群设计最核心的两个概念。<br> 配置不合理时，扩容、恢复和查询性能都会受影响。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>primary shard</li><li>replica shard</li><li>分片路由基础</li><li>集群恢复</li><li>故障转移</li><li>读写路径认知</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解分片是扩展单元，副本是容灾单元</li><li>理解分片数量不是越多越好</li><li>理解副本可以提升读取能力但会增加写入成本</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>创建过多小分片</li><li>只看容量，不看恢复成本</li><li>误以为副本越多越好</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>设计一个中等规模索引的分片策略</li><li>比较副本数变化对系统的影响</li><li>总结 ES 高可用设计的基本原则</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>分片和副本分别主要解决什么问题</li><li>为什么分片数量会影响集群稳定性</li><li>副本为什么既提升可用性又带来成本</li></ul>',15)])])}con